#!/usr/bin/env python3
"""DGX DEPLOY v19.34.245 — EOD close honours trade-style (stop sweeping position/swing).
Both EOD paths (auto check_eod_close + manual /eod-close-now) now resolve close_at_eod
from the trade-style POLICY via should_close_at_eod(), not a per-trade attribute that was
wrongly default-True for position setups. Long-horizon styles held overnight; scalp/intraday
still close. Idempotent: rewrite files, pytest, git commit && git push, restart."""
import base64, gzip, os, subprocess, sys
FILES = {
    'backend/services/order_policy_registry.py': '',
    'backend/services/position_manager.py': '',
    'backend/routers/trading_bot.py': '',
    'backend/services/opportunity_evaluator.py': '',
    'backend/tests/test_v19_34_245_eod_trade_style.py': '',
}
REPO=os.getcwd()
def main():
    if not os.path.isdir(os.path.join(REPO,"backend","services")):
        print("[FATAL] not repo root"); sys.exit(1)
    for rel,b in FILES.items():
        dst=os.path.join(REPO,rel); os.makedirs(os.path.dirname(dst),exist_ok=True)
        data=gzip.decompress(base64.b64decode(b)); open(dst,"wb").write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")
    print("[TEST] pytest v245 ...")
    r=subprocess.run([sys.executable,"-m","pytest","backend/tests/test_v19_34_245_eod_trade_style.py","-q"],cwd=REPO)
    if r.returncode!=0: print("[FATAL] pytest failed — aborting."); sys.exit(2)
    subprocess.run(["git","add"]+list(FILES.keys()),cwd=REPO)
    c=subprocess.run(["git","commit","-m","v19.34.245 — EOD close honours trade-style policy (no more sweeping position/swing)"],cwd=REPO)
    if c.returncode!=0: print("[INFO] commit no-op")
    p=subprocess.run(["git","push"],cwd=REPO)
    if p.returncode!=0: print("[WARN] push failed — commit is local")
    print("[RESTART] ./start_backend.sh --force"); subprocess.run(["./start_backend.sh","--force"],cwd=REPO)
    print("[DONE] v19.34.245 deployed.")
if __name__=="__main__": main()
